### Implementation Report: Double Jump & Signal Leak Fix
**Target File:** `player.gd` | **Engine:** Godot 4.x | **Constraint:** Zero pool allocation.

#### 1. Logic Implementation
Integrated the double jump mechanic using primitive counters to avoid heap allocation and implemented a safe signal connection pattern to prevent memory leaks.

```gdscript
extends CharacterBody2D
class_name Player

@export var speed: float = 250.0
@export var jump_velocity: float = -400.0

# State variables (Primitive types for zero pool allocation)
var jump_count: int = 0
const MAX_JUMPS: int = 2

func _physics_process(delta: float) -> void:
	# Reset jump counter upon landing
	if is_on_floor():
		jump_count = 0

	# Double Jump Logic
	if Input.is_action_just_pressed("jump") and jump_count < MAX_JUMPS:
		velocity.y = jump_velocity
		jump_count += 1

	# Basic Movement (Placeholder for MVP)
	var direction := Input.get_axis("ui_left", "ui_right")
	if direction:
		velocity.x = direction * speed
	else:
		velocity.x = move_toward(velocity.x, 0, speed)

	move_and_slide()

# --- Signal Leak Fixes ---

func _on_hit(dmg: int) -> void:
	print("Damage taken: ", dmg)

## Safe connection method to be called by external entities (Enemies/Projectiles)
## Prevents duplicate connections and utilizes one-shot flags for transient objects
func connect_to_damage_source(source: Node) -> void:
	if source.has_signal("hit_signal"):
		if not source.hit_signal.is_connected(_on_hit):
			# CONNECT_ONE_SHOT prevents leak for transient objects (e.g. projectiles)
			source.hit_signal.connect(_on_hit, CONNECT_ONE_SHOT)

